import 'dart:io'; import '../../../../core/constants/storage_paths.dart'; import '../../../../core/services/firebase/storage_service.dart'; import '../../domain/repositories/chat_media_repository.dart';
class ChatMediaRepositoryImpl implements ChatMediaRepository{final StorageService storage; const ChatMediaRepositoryImpl(this.storage); @override Future<String> uploadChatImage({required String roomId,required String senderId,required File image})=>storage.uploadFile(file:image,path:StoragePaths.chatImage(chatId:roomId,senderId:senderId,fileName:'${DateTime.now().millisecondsSinceEpoch}.jpg'),contentType:'image/jpeg'); @override Future<void> deleteChatImageByUrl(String imageUrl)=>storage.deleteFileByUrl(imageUrl);}
